# High-Performance Object Pooling Framework

Below is a comprehensive pooling framework designed for high-throughput ETL pipelines. This solution provides generalized pooling with powerful features including metrics, validation, and automatic reset logic.

## Core Framework

```go
package pooling

import (
	"reflect"
	"runtime"
	"sync"
	"sync/atomic"
	"time"
	"unsafe"

	"github.com/prometheus/client_golang/prometheus"
)

// Pool statistics
type PoolStats struct {
	Gets         atomic.Int64
	Puts         atomic.Int64
	Misses       atomic.Int64
	Hits         atomic.Int64
	Resets       atomic.Int64
	ResetErrors  atomic.Int64
	Size         atomic.Int64
	MaxSize      int64 // Not atomic because it's only read during stats
	AverageStay  time.Duration
	LastResized  time.Time
	Created      time.Time
	ObjectType   string
	PoolName     string
	RecentErrors []string // Circular buffer of recent errors
}

// Reset interface for pooled objects
type Resettable interface {
	Reset() error
}

// Enhanced sync.Pool with metrics and safety features
type EnhancedPool[T any] struct {
	pool        sync.Pool
	validator   func(T) error
	resetter    func(T) error
	initializer func(T)
	stats       PoolStats
	maxSize     int64
	metrics     bool
	debug       bool

	// For prometheus metrics
	promHits    prometheus.Counter
	promMisses  prometheus.Counter
	promSize    prometheus.Gauge
	promResets  prometheus.Counter
	promLatency prometheus.Histogram
}

// Configuration options for the pool
type PoolConfig[T any] struct {
	Factory     func() T      // Function to create new objects
	Validator   func(T) error // Optional function to validate returned objects
	Resetter    func(T) error // Optional function to reset objects
	Initializer func(T)       // Optional function to initialize/prep objects before returning
	MaxSize     int64         // Max objects in pool (0 = unlimited)
	Name        string        // Name for metrics
	WithMetrics bool          // Enable Prometheus metrics
	Debug       bool          // Enable debug mode with extra checks
}

// Create a new enhanced pool
func NewPool[T any](config PoolConfig[T]) *EnhancedPool[T] {
	ep := &EnhancedPool[T]{
		validator:   config.Validator,
		resetter:    config.Resetter,
		initializer: config.Initializer,
		maxSize:     config.MaxSize,
		metrics:     config.WithMetrics,
		debug:       config.Debug,
	}

	// Set pool stats
	ep.stats.Created = time.Now()
	ep.stats.LastResized = time.Now()
	ep.stats.PoolName = config.Name
	ep.stats.MaxSize = config.MaxSize

	// Detect type name for metrics
	t := reflect.TypeOf(config.Factory())
	typeName := t.String()
	if t.Kind() == reflect.Ptr {
		typeName = "*" + t.Elem().Name()
	} else {
		typeName = t.Name()
	}
	ep.stats.ObjectType = typeName

	// Initialize prometheus metrics if enabled
	if ep.metrics {
		ep.initPrometheusMetrics(config.Name, typeName)
	}

	// Configure the underlying pool
	ep.pool = sync.Pool{
		New: func() interface{} {
			ep.stats.Misses.Add(1)
			if ep.metrics {
				ep.promMisses.Inc()
			}

			// If at max size, return nil and let caller handle
			if ep.maxSize > 0 && ep.stats.Size.Load() >= ep.maxSize {
				return nil
			}

			ep.stats.Size.Add(1)
			if ep.metrics {
				ep.promSize.Inc()
			}

			return config.Factory()
		},
	}

	return ep
}

// Initialize Prometheus metrics
func (ep *EnhancedPool[T]) initPrometheusMetrics(poolName, typeName string) {
	labels := prometheus.Labels{
		"pool": poolName,
		"type": typeName,
	}

	ep.promHits = prometheus.NewCounter(prometheus.CounterOpts{
		Name:        "pool_hits_total",
		Help:        "Number of times an object was reused from the pool",
		ConstLabels: labels,
	})

	ep.promMisses = prometheus.NewCounter(prometheus.CounterOpts{
		Name:        "pool_misses_total",
		Help:        "Number of times a new object had to be created",
		ConstLabels: labels,
	})

	ep.promSize = prometheus.NewGauge(prometheus.GaugeOpts{
		Name:        "pool_size",
		Help:        "Current estimated size of the pool",
		ConstLabels: labels,
	})

	ep.promResets = prometheus.NewCounter(prometheus.CounterOpts{
		Name:        "pool_resets_total",
		Help:        "Number of times objects were reset",
		ConstLabels: labels,
	})

	ep.promLatency = prometheus.NewHistogram(prometheus.HistogramOpts{
		Name:        "pool_object_lifetime_seconds",
		Help:        "Time objects spend outside the pool",
		ConstLabels: labels,
		Buckets:     []float64{0.001, 0.01, 0.1, 1, 10},
	})

	// Register with prometheus
	prometheus.MustRegister(
		ep.promHits,
		ep.promMisses, 
		ep.promSize,
		ep.promResets,
		ep.promLatency,
	)
}

// Get an object from the pool
func (ep *EnhancedPool[T]) Get() T {
	startTime := time.Now()
	ep.stats.Gets.Add(1)

	// Get from underlying pool
	obj := ep.pool.Get()
	if obj == nil {
		// Factory returned nil because we're at max size
		// Create a temporary object that won't be returned to pool
		var zero T
		return zero
	}

	item := obj.(T)

	// Initialize if needed
	if ep.initializer != nil {
		ep.initializer(item)
	}

	// Track stats
	if ep.detectFreshAllocation(item) {
		ep.stats.Hits.Add(1)
		if ep.metrics {
			ep.promHits.Inc()
		}
	}

	// Store acquisition time for latency tracking
	if ep.metrics {
		// Store creation time in a hidden field for latency tracking
		// This uses unsafe to avoid requiring pooled objects to implement an interface
		storeCreationTime(item, startTime)
	}

	return item
}

// Put an object back in the pool
func (ep *EnhancedPool[T]) Put(item T) {
	// Skip nil objects
	if isNil(item) {
		return
	}

	ep.stats.Puts.Add(1)

	// Track object lifetime if metrics enabled
	if ep.metrics {
		if ts := retrieveCreationTime(item); !ts.IsZero() {
			duration := time.Since(ts)
			ep.promLatency.Observe(duration.Seconds())
			ep.stats.AverageStay = time.Duration(
				(ep.stats.AverageStay.Nanoseconds()*9 + duration.Nanoseconds()) / 10,
			)
		}
	}

	// Check if object implements Resettable
	if r, ok := any(item).(Resettable); ok {
		if err := r.Reset(); err != nil {
			ep.stats.ResetErrors.Add(1)
			if ep.debug {
				// In debug mode, we track the most recent errors
				addRecentError(&ep.stats, err.Error())
			}
			return // Don't put broken objects back in pool
		}
		ep.stats.Resets.Add(1)
		if ep.metrics {
			ep.promResets.Inc()
		}
	} else if ep.resetter != nil {
		// Use custom resetter if provided
		if err := ep.resetter(item); err != nil {
			ep.stats.ResetErrors.Add(1)
			if ep.debug {
				addRecentError(&ep.stats, err.Error())
			}
			return // Don't put broken objects back in pool
		}
		ep.stats.Resets.Add(1)
		if ep.metrics {
			ep.promResets.Inc()
		}
	}

	// Validate object if validator provided
	if ep.validator != nil && ep.debug {
		if err := ep.validator(item); err != nil {
			addRecentError(&ep.stats, "Validation error: "+err.Error())
			return // Don't put invalid objects back in pool
		}
	}

	// Finally return to underlying pool
	ep.pool.Put(item)
}

// Get pool statistics
func (ep *EnhancedPool[T]) Stats() PoolStats {
	return ep.stats
}

// Helper: detect if object was freshly allocated
func (ep *EnhancedPool[T]) detectFreshAllocation(item T) bool {
	// Use a simple heuristic based on pointer value
	// This is a best-effort detection and may not be perfect
	ptr := reflect.ValueOf(item).Pointer()
	return ptr != 0 // Non-zero pointer suggests reuse
}

// Helper: add recent error to circular buffer
func addRecentError(stats *PoolStats, errMsg string) {
	if len(stats.RecentErrors) < 10 {
		stats.RecentErrors = append(stats.RecentErrors, errMsg)
	} else {
		// Circular buffer
		stats.RecentErrors = append(stats.RecentErrors[1:], errMsg)
	}
}

// Helper: check if an interface value is nil
func isNil(v interface{}) bool {
	if v == nil {
		return true
	}
	rv := reflect.ValueOf(v)
	return rv.Kind() == reflect.Ptr && rv.IsNil()
}

// Store creation time in a hidden field for latency tracking
func storeCreationTime(item interface{}, t time.Time) {
	// This is a dangerous hack that works by finding padding bytes in structs
	// and using them to store metadata. Only use in advanced applications!
