// Retrieve creation time from the hidden field
func retrieveCreationTime(item interface{}) time.Time {
	value := reflect.ValueOf(item)
	if value.Kind() == reflect.Ptr && !value.IsNil() {
		return getUniquePoolTimestamp(unsafe.Pointer(value.Pointer()))
	}
