// Global map to store timestamps - a real implementation might use atomic.Value
// or other techniques to avoid this global mutex
var (
	timestampsMu sync.Mutex
	timestamps   = make(map[uintptr]time.Time)
)

func setUniquePoolTimestamp(ptr unsafe.Pointer, t time.Time) {
	timestampsMu.Lock()
	defer timestampsMu.Unlock()
	timestamps[uintptr(ptr)] = t
