func getUniquePoolTimestamp(ptr unsafe.Pointer) time.Time {
	timestampsMu.Lock()
	defer timestampsMu.Unlock()
	t, _ := timestamps[uintptr(ptr)]
	delete(timestamps, uintptr(ptr)) // Clean up
