// Helper to clean up and return pooled objects
func cleanupModel(model *transform.MessageModel) {
	if model == nil {
		return
	}

	// First return all IndexDocumentChangeModels to their pool
	for indexKey, models := range model.Changes {
		for _, indexModel := range models {
			indexDocModelPool.Put(indexModel)
		}
		// Clear the slice to avoid memory leaks
		model.Changes[indexKey] = nil
	}

	// Then return the MessageModel itself
	messageModelPool.Put(model)
