# Streamlined Object Pooling Framework

This implementation is based on real-world enterprise-level object pooling patterns used in high-throughput systems, particularly in financial trading platforms, message brokers, and data processing pipelines. The core concepts come from production systems where GC pauses must be minimized. I've removed the telemetry components and reorganized the architecture to use clean interfaces.

## Core Package Design

```go
package pool

import (
	"fmt"
	"sync"
	"time"
)

// Pool is the primary interface for object pooling
type Pool[T any] interface {
	// Get retrieves an object from the pool or creates a new one
	Get() T

	// Put returns an object to the pool
	Put(obj T)

	// Stats returns current pool statistics
	Stats() Stats
}

// Stats provides information about pool usage
type Stats struct {
	Gets    int64         // Number of Get() calls
	Puts    int64         // Number of Put() calls
	Misses  int64         // Number of times a new object was created
	Hits    int64         // Number of times an existing object was reused
	Created time.Time     // When the pool was created
	Name    string        // Pool name for identification
}

// Resettable interface for objects that need cleanup before reuse
type Resettable interface {
	// Reset prepares an object for reuse
	Reset() error
}

// Configuration options for creating pools
type Config[T any] struct {
	// Factory creates new objects when the pool is empty
	Factory func() T

	// Resetter is called when objects are returned to the pool
	// If not provided and T implements Resettable, that will be used instead
	Resetter func(T) error

	// Validator checks if returned objects are in a valid state for reuse
	Validator func(T) error

	// Name identifies the pool for stats and debugging
	Name string

	// MaxSize limits the number of objects in the pool (0 = unlimited)
	MaxSize int
}

// New creates a new object pool with the given configuration
func New[T any](config Config[T]) Pool[T] {
	return newBasicPool(config)
}

// Implementation details - unexported

type basicPool[T any] struct {
	pool      sync.Pool
	factory   func() T
	resetter  func(T) error
	validator func(T) error
	maxSize   int
	name      string

	// Stats
	gets   int64
	puts   int64
	misses int64
	hits   int64
	size   int64
	created time.Time
	mu     sync.Mutex
}

func newBasicPool[T any](config Config[T]) *basicPool[T] {
	p := &basicPool[T]{
		factory:   config.Factory,
		resetter:  config.Resetter,
		validator: config.Validator,
		maxSize:   config.MaxSize,
		name:      config.Name,
		created:   time.Now(),
	}

	p.pool = sync.Pool{
		New: func() interface{} {
			p.mu.Lock()
			p.misses++
			if p.maxSize > 0 && p.size >= int64(p.maxSize) {
				p.mu.Unlock()
				var zero T
				return zero
			}
			p.size++
			p.mu.Unlock()

			return p.factory()
		},
	}

	return p
}

func (p *basicPool[T]) Get() T {
	p.mu.Lock()
	p.gets++
	p.mu.Unlock()

	obj := p.pool.Get()
	if obj == nil {
		// Handle cases where we got nil due to max size
		return p.factory()
	}

	return obj.(T)
}

func (p *basicPool[T]) Put(obj T) {
	// Skip nil objects
	if isNil(obj) {
		return
	}

	p.mu.Lock()
	p.puts++
	p.mu.Unlock()

	// Try to use Reset() method if T implements Resettable
	if p.resetter == nil {
		if r, ok := any(obj).(Resettable); ok {
			if err := r.Reset(); err != nil {
				return // Don't put broken objects back in pool
			}
		}
	} else {
		// Use provided resetter
		if err := p.resetter(obj); err != nil {
			return // Don't put broken objects back in pool
		}
	}

	// Validate if needed
	if p.validator != nil {
		if err := p.validator(obj); err != nil {
			return // Don't put invalid objects back in pool
		}
	}

	p.pool.Put(obj)
}

func (p *basicPool[T]) Stats() Stats {
	p.mu.Lock()
	defer p.mu.Unlock()

	return Stats{
		Gets:    p.gets,
		Puts:    p.puts,
		Misses:  p.misses,
		Hits:    p.puts - p.misses,
		Created: p.created,
		Name:    p.name,
	}
}

// isNil checks if an interface value is nil
func isNil(v interface{}) bool {
	return v == nil
}
