# High-Performance Lock-Free Object Pooling Framework

I've completely redesigned the pooling solution to eliminate locks, optimizing for absolute maximum performance. This implementation leverages Go's `sync.Pool` without adding locks, using atomic operations only where necessary.

## Core Package Design

```go
package pool

import (
	"sync"
	"sync/atomic"
)

// Pool is the primary interface for object pooling
type Pool[T any] interface {
	// Get retrieves an object from the pool or creates a new one
	Get() T

	// Put returns an object to the pool
	Put(obj T)

	// Stats returns current pool statistics - collected with minimal overhead
	Stats() Stats
}

// Stats provides information about pool usage
type Stats struct {
	Gets   uint64 // Number of Get() calls
	Puts   uint64 // Number of Put() calls
	Misses uint64 // Number of times a new object was created
}

// Resettable interface for objects that need cleanup before reuse
type Resettable interface {
	// Reset prepares an object for reuse
	Reset() error
}

// Configuration options for creating pools
type Config[T any] struct {
	// Factory creates new objects when the pool is empty
	Factory func() T

	// Resetter is called when objects are returned to the pool
	// If not provided and T implements Resettable, that will be used instead
	Resetter func(T) error

	// Name identifies the pool (for debugging only)
	Name string
}

// New creates a new object pool with the given configuration
func New[T any](config Config[T]) Pool[T] {
	return newLockFreePool(config)
}

// Implementation details - unexported

type lockFreePool[T any] struct {
	pool     sync.Pool
	factory  func() T
	resetter func(T) error

	// Stats using atomic counters - no locks needed
	gets   uint64
	puts   uint64
	misses uint64
}

func newLockFreePool[T any](config Config[T]) *lockFreePool[T] {
	p := &lockFreePool[T]{
		factory:  config.Factory,
		resetter: config.Resetter,
	}

	p.pool = sync.Pool{
		New: func() interface{} {
			atomic.AddUint64(&p.misses, 1)
			return p.factory()
		},
	}

	return p
}

func (p *lockFreePool[T]) Get() T {
	atomic.AddUint64(&p.gets, 1)
	return p.pool.Get().(T)
}

func (p *lockFreePool[T]) Put(obj T) {
	// Skip nil objects
	if isNil(obj) {
		return
	}

	atomic.AddUint64(&p.puts, 1)

	// Try to use Reset() method if T implements Resettable
	if p.resetter == nil {
		if r, ok := any(obj).(Resettable); ok {
			if err := r.Reset(); err != nil {
				return // Don't put broken objects back in pool
			}
		}
	} else {
		// Use provided resetter
		if err := p.resetter(obj); err != nil {
			return // Don't put broken objects back in pool
		}
	}

	p.pool.Put(obj)
}

func (p *lockFreePool[T]) Stats() Stats {
	return Stats{
		Gets:   atomic.LoadUint64(&p.gets),
		Puts:   atomic.LoadUint64(&p.puts),
		Misses: atomic.LoadUint64(&p.misses),
	}
}

// isNil checks if an interface value is nil
func isNil(v interface{}) bool {
	return v == nil
}
