	// Initialize fresh maps
	model.Properties = p.propertiesPool.Get()
	model.DocumentKeys = p.documentKeysPool.Get()
	model.EventMetadata = p.metadataPool.Get()

	return model
}

func (p *indexDocModelPool) Put(model *IndexDocumentChangeModel) {
