// MessageModelPool manages pools of MessageModel objects
type MessageModelPool interface {
	// Get retrieves a message model with changes map initialized
	Get() *MessageModel

	// Put returns a model to the pool
	Put(model *MessageModel)

	// Clean releases a model and all its document models back to their pools
	Clean(model *MessageModel, docPool IndexDocumentModelPool)

	// Stats returns usage statistics
	Stats() Stats
}

// Create a new MessageModelPool
func NewMessageModelPool() MessageModelPool {
	changesPool := NewMapPool[string, []*IndexDocumentChangeModel](8, "changes")

	return &messageModelPool{
		modelPool: New(Config[*MessageModel]{
			Factory: func() *MessageModel {
				return &MessageModel{
					Changes: changesPool.Get(),
				}
			},
			Resetter: func(model *MessageModel) error {
				// Return changes map to its pool
				if model.Changes != nil {
					changesPool.Put(model.Changes)
				}

				// Clear key and references
				model.Key = nil
				model.OriginalMessage = nil
				model.DeadLetterMessage = nil
				model.LogContext = nil

				return nil
			},
			Name: "message-model",
		}),
		changesPool: changesPool,
	}
}

type messageModelPool struct {
	modelPool   Pool[*MessageModel]
	changesPool MapPool[string, []*IndexDocumentChangeModel]
}

func (p *messageModelPool) Get() *MessageModel {
	model := p.modelPool.Get()
	model.Changes = p.changesPool.Get()
	return model
}

func (p *messageModelPool) Put(model *MessageModel) {
	if model == nil {
		return
	}
	p.modelPool.Put(model)
}

func (p *messageModelPool) Clean(model *MessageModel, docPool IndexDocumentModelPool) {
	if model == nil {
		return
	}

	// First put all document models back to their pool
	for _, docs := range model.Changes {
		for _, doc := range docs {
			docPool.Put(doc)
		}
	}

	// Then put the message model back
	p.Put(model)
}

func (p *messageModelPool) Stats() Stats {
	return p.modelPool.Stats()
}
