# Measuring Pool Performance with Feature Flags

Yes, using feature flags is an excellent approach for performance testing your pooling implementation. Here's how to set it up properly to get reliable measurements:

## Implementation with Feature Flags

```go
// Pool factory with feature flag support
type PoolFactory struct {
    docModelPool      IndexDocumentModelPool
    msgModelPool      MessageModelPool
    propertiesPool    MapPool[string, any]
    documentKeysPool  MapPool[string, any]
    metadataPool      MapPool[string, any]
    poolingEnabled    func() bool // Feature flag function
}

// Create a new factory with feature flag
func NewPoolFactory(isPoolingEnabled func() bool) *PoolFactory {
    docPool := NewIndexDocumentModelPool()
    msgPool := NewMessageModelPool()

    // Extract sub-pools to use directly
    docPoolImpl := docPool.(*indexDocModelPool)

    return &PoolFactory{
        docModelPool:     docPool,
        msgModelPool:     msgPool,
        propertiesPool:   docPoolImpl.propertiesPool,
        documentKeysPool: docPoolImpl.documentKeysPool,
        metadataPool:     docPoolImpl.metadataPool,
        poolingEnabled:   isPoolingEnabled,
    }
}

// Get document model with/without pooling based on feature flag
func (f *PoolFactory) GetDocumentModel() *IndexDocumentChangeModel {
    if f.poolingEnabled() {
        return f.docModelPool.Get()
    }

    // Non-pooled version - direct allocation
    return &IndexDocumentChangeModel{
        Properties:    make(map[string]any),
        DocumentKeys:  make(map[string]any),
        EventMetadata: make(map[string]any),
        PartialKey:    make([]string, 0),
    }
}

// Return document model to pool if pooling is enabled
func (f *PoolFactory) PutDocumentModel(model *IndexDocumentChangeModel) {
    if model == nil {
        return
    }

    if f.poolingEnabled() {
        f.docModelPool.Put(model)
    }
    // When pooling is disabled, let GC handle it
}

// Get message model with/without pooling
func (f *PoolFactory) GetMessageModel() *MessageModel {
    if f.poolingEnabled() {
        return f.msgModelPool.Get()
    }

    // Non-pooled version
    return &MessageModel{
        Changes: make(map[string][]*IndexDocumentChangeModel),
    }
}

// Return message model to pool if enabled
func (f *PoolFactory) PutMessageModel(model *MessageModel) {
    if model == nil {
        return
    }

    if f.poolingEnabled() {
        f.msgModelPool.Put(model)
    }
    // When pooling is disabled, let GC handle it
}

// Clean up a message and all its document models
func (f *PoolFactory) CleanupMessageModel(model *MessageModel) {
    if model == nil {
        return
    }

    if f.poolingEnabled() {
        f.msgModelPool.Clean(model, f.docModelPool)
    }
    // When pooling is disabled, let GC handle it
}

// Get a map with/without pooling
func (f *PoolFactory) GetPropertiesMap() map[string]any {
    if f.poolingEnabled() {
        return f.propertiesPool.Get()
    }
    return make(map[string]any)
}
