6. **GC Stats**: Track GC frequency and pause times with the runtime package:

```go
var lastGC uint32
var gcPauses []time.Duration

func monitorGC() {
    ticker := time.NewTicker(time.Millisecond * 10)
    for range ticker.C {
        var stats runtime.MemStats
        runtime.ReadMemStats(&stats)

        if stats.NumGC > lastGC {
            // Record pause times for new GCs
            for i := lastGC; i < stats.NumGC; i++ {
                idx := i % 256
                pause := time.Duration(stats.PauseNs[idx])
                gcPauses = append(gcPauses, pause)
            }
            lastGC = stats.NumGC
        }
    }
}
```

