	"airwatch/uem/gumdrop-ingestion/pkg/telemetry/datadog"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry/metrics"

	goMetrics "github.com/rcrowley/go-metrics"
)

const defaultImplementation string = "datadog"

type registryCtor func(*log.Context, *config.Registry, *string) (metrics.Registry, error)

type implementationInfo struct {
	ctor      registryCtor
	separator string
}

// Module state

var defaultRegistryImplementation metrics.Registry = nullRegistry{}
var registry = defaultRegistryImplementation
var currentImplementationInfo *implementationInfo

// registryImplementations holds the available metrics registry implementations information.
//
// The implementation names must use all lowercase characters.
var registryImplementations = map[string]*implementationInfo{
	"datadog": {
		ctor:      datadog.NewRegistry,
		separator: datadog.TagsSeparator,
	},
}

var errImplementationNotFound = errors.New("metrics registry implementation not found")

// InitRegistryFromConfig initializes the metrics registry.
//
// This function should be used once during application startup.
//
// This function is not thread safe. But it's OK since it should
// only be called during application startup.
func InitRegistryFromConfig(
	logContext *log.Context,
	registryConfig *config.Registry,
	additionalTags *string,
) error {
	if registry != defaultRegistryImplementation {
		return nil
	}

	info, err := getImplementationInfo()
	if err != nil {
		return err
	}

	newRegistry, err := info.ctor(logContext, registryConfig, additionalTags)
	if err != nil {
		return err
	}

	registry = newRegistry
	return nil
}

// InitRegistryFromFile initializes the metrics registry.
//
// This function should be used once during application startup.
//
// This function is not thread safe. But it's OK since it should
// only be called during application startup.
func InitRegistryFromFile(logContext *log.Context, configPath string, additionalTags *string) error {
	registryConfig, err := config.LoadRegistryConfiguration(configPath)
	if err != nil {
		return err
	}

	return InitRegistryFromConfig(logContext, registryConfig, additionalTags)
}

// SubscribeToMetricRegistries creates reporter to publish metrics from other metric registries.
func SubscribeToMetricRegistries(
	logContext *log.Context,
	prefix string,
	registries ...goMetrics.Registry,
) ([]metrics.Reporter, error) {
	return getRegistry().SubscribeToAdditionalRegistries(logContext, prefix, registries...)
}

// AppendTags concatenates the specified tags to the config map using the
// current implementation separator.
//
// This function is not thread safe. But it's OK since it should
// only be called during application startup.
func AppendTags(conf map[string]string, tags string) error {
	info, err := getImplementationInfo()
	if err != nil {
		return err
	}

	config.AppendTags(conf, tags, info.separator)
	return nil
}

// CloseRegistry frees all the resources of the current metrics registry.
func CloseRegistry(logContext *log.Context) {
	err := getRegistry().Close()
	err = errorHandling.HandleError(
		func() *log.Context {
			return logContext
		}, err,
	)
	registry = defaultRegistryImplementation
}

// GetMetricsGroup returns a metrics group by name.
func GetMetricsGroup(logContext *log.Context, name string) metrics.Group {
	return getRegistry().GetGroup(logContext, name)
}

// Increment increments a counter delta by 1.
func Increment(logContext *log.Context, group string, metricName string, tags ...metrics.Tag) {
	counter := getRegistry().GetGroup(logContext, group).GetCounter(logContext, metricName)
	counter.With(tags...).Add(1)
}

func IncrementFailure(
	logContext *log.Context,
	group string,
	baseMetricName string,
	tags ...metrics.Tag,
) {
	registryConfig := getRegistry().GetConfig()
	counterName := registryConfig.JoinMetricNames(
		logContext, baseMetricName,
		metrics.MeasureFailureCounterSuffix,
	)
	Count(logContext, group, counterName, 1, tags...)
}

// Count adds a delta to a counter.
func Count(logContext *log.Context, group string, metricName string, delta int64, tags ...metrics.Tag) {
	counter := getRegistry().GetGroup(logContext, group).GetCounter(logContext, metricName)
	counter.With(tags...).Add(delta)
}

// Gauge sets the value of a gauge.
func Gauge(logContext *log.Context, group string, metricName string, value float64, tags ...metrics.Tag) {
	gauge := getRegistry().GetGroup(logContext, group).GetGauge(logContext, metricName)
	gauge.With(tags...).Set(value)
}

// Timing sets the value of a timer.
func Timing(logContext *log.Context, group string, metricName string, value time.Duration, tags ...metrics.Tag) {
	registryConfig := getRegistry().GetConfig()
	timerName := registryConfig.JoinMetricNames(logContext, metricName, metrics.MeasureLatencySuffix)
	timer := getRegistry().GetGroup(logContext, group).GetTimer(logContext, timerName)
	timer.With(tags...).Set(value)
}

// Measure measures the execution of an action. It stores the execution time in a gauge,
// and keeps track of the number of times the action was executed in a counter.
func Measure(logContext *log.Context, group string, baseMetricName string, action func(), tags ...metrics.Tag) {
	start := time.Now()
	action()
	elapsed := time.Since(start)
	registryConfig := getRegistry().GetConfig()
	counterName := registryConfig.JoinMetricNames(logContext, baseMetricName, metrics.MeasureCallCounterSuffix)
	Timing(logContext, group, baseMetricName, elapsed, tags...)
	Count(logContext, group, counterName, 1, tags...)
}

// MeasureWithResult measures the execution of a function. It stores the execution time in a gauge,
// and keeps track of the number of times the function was executed in a counter. If the result type
// is 'error', it tracks the failures in another counter.
func MeasureWithResult[TResult any](
	logContext *log.Context,
	group string,
	baseMetricName string,
	fn func() TResult,
	tags ...metrics.Tag,
) TResult {
	var result TResult
	Measure(
		logContext, group, baseMetricName, func() {
			result = fn()
		}, tags...,
	)

	// Count failures...
	var tmp any = result
	if err, ok := tmp.(error); ok && err != nil {
		IncrementFailure(logContext, group, baseMetricName, tags...)
	}

	return result
}

// MeasureWithResultAndError measures the execution of a function. It stores the execution time in a gauge,
// and keeps track of the number of times the function was executed in a counter. If the result type
// is 'error', it tracks the failures in another counter.
func MeasureWithResultAndError[TResult any](
	logContext *log.Context,
	group string,
	baseMetricName string,
	fn func() (TResult, error),
	tags ...metrics.Tag,
) (TResult, error) {
	var result TResult
	var err error
	Measure(
		logContext, group, baseMetricName, func() {
			result, err = fn()
		}, tags...,
	)
	if err != nil {
		IncrementFailure(logContext, group, baseMetricName, tags...)
	}
	return result, err
}

// MeasureWithResultAndErrorExcludingError measures the execution of a function. It stores the execution time in a gauge,
// and keeps track of the number of times the function was executed in a counter. If the result type
// is 'error' AND NOT exluded, it tracks the failures in another counter.
// An error is excluded when includeErrorFunc returns false.
func MeasureWithResultAndErrorExcludingError[TResult any](
	logContext *log.Context,
	group string,
	baseMetricName string,
	fn func() (TResult, error),
	includeErrorFunc func(error) bool,
	tags ...metrics.Tag,
) (result TResult, excluded bool, err error) {
	Measure(
		logContext, group, baseMetricName, func() {
			result, err = fn()
		}, tags...,
	)
	if err != nil && includeErrorFunc(err) {
		IncrementFailure(logContext, group, baseMetricName, tags...)
		return result, false, err
	}

	return result, true, err
}

// MeasureWithError measures the execution of a function. It stores the execution time in a gauge,
// and keeps track of the number of times the function was executed in a counter.
// Tracks the failures in another counter.
// This method was added because type assertions on wrapped errors do not work.
func MeasureWithError(
	logContext *log.Context,
	group string,
	baseMetricName string,
	fn func() error,
	tags ...metrics.Tag,
) error {
	var err error
	Measure(
		logContext, group, baseMetricName, func() {
			err = fn()
		}, tags...,
	)

	// Count failures...
	if err != nil {
		IncrementFailure(logContext, group, baseMetricName, tags...)
	}

	return err
}

// MeasureWithResultsAndError measures the execution of a function. It stores the execution time in a gauge,
// and keeps track of the number of times the function was executed in a counter. If the result type
// is 'error', it tracks the failures in another counter.
func MeasureWithResultsAndError[TResult any, TResult2 any](
	logContext *log.Context,
	group string,
	baseMetricName string,
	fn func() (TResult, TResult2, error),
	tags ...metrics.Tag,
) (result TResult, result2 TResult2, err error) {
	Measure(
		logContext, group, baseMetricName, func() {
			result, result2, err = fn()
		}, tags...,
	)
	if err != nil {
		IncrementFailure(logContext, group, baseMetricName, tags...)
	}
	return result, result2, err
}

// getRegistry returns the current metrics registry.
func getRegistry() metrics.Registry {
	return registry
}

// getImplementationInfo return the current implementation information.
//
// This method is not thread safe. But it's OK since it should only be
// called during application startup.
func getImplementationInfo() (*implementationInfo, error) {
	if currentImplementationInfo == nil {
		implementation := env.LookupValue(Implementation, defaultImplementation)
		info, found := registryImplementations[strings.ToLower(strings.TrimSpace(implementation))]
		if !found {
			return nil, errImplementationNotFound
		}

		currentImplementationInfo = info
	}

	return currentImplementationInfo, nil
}
