# Implementing Object Pooling with Custom Metrics Integration

Let's create a comprehensive object pooling implementation that integrates with your custom metrics system. I'll focus on high performance while providing useful metrics.

## Core Pooling Package with Custom Metrics

```go
package pool

import (
	"sync"
	"sync/atomic"
	"time"

	"airwatch/uem/gumdrop-ingestion/pkg/log"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry/metrics"
)

// Metric names
const (
	MetricGroupPool      = "pool"
	MetricGet            = "get"
	MetricPut            = "put"
	MetricMiss           = "miss"
	MetricHit            = "hit"
	MetricObjectLifetime = "object_lifetime"
	MetricResets         = "resets"
	MetricResetErrors    = "reset_errors"
)

// Pool is the primary interface for object pooling
type Pool[T any] interface {
	// Get retrieves an object from the pool or creates a new one
	Get() T

	// Put returns an object to the pool
	Put(obj T)

	// Stats returns current pool statistics
	Stats() Stats
}

// Stats provides information about pool usage
type Stats struct {
	Gets        uint64
	Puts        uint64
	Misses      uint64
	Hits        uint64
	Resets      uint64
	ResetErrors uint64
}

// Resettable interface for objects that need cleanup before reuse
type Resettable interface {
	// Reset prepares an object for reuse
	Reset() error
}

// Configuration options for creating pools
type Config[T any] struct {
	// Factory creates new objects when the pool is empty
	Factory func() T

	// Resetter is called when objects are returned to the pool
	// If not provided and T implements Resettable, that will be used instead
	Resetter func(T) error

	// Name identifies the pool (for metrics and debugging)
	Name string

	// EnableMetrics toggles metrics collection
	EnableMetrics bool

	// ObjectLifetimeTracking enables measuring how long objects are used outside the pool
	TrackObjectLifetime bool
}

// New creates a new object pool with the given configuration
func New[T any](config Config[T]) Pool[T] {
	return newPerformancePool(config)
}

// Implementation

type performancePool[T any] struct {
	pool     sync.Pool
	factory  func() T
	resetter func(T) error

	// Stats using atomic counters - no locks
	gets        uint64
	puts        uint64
	misses      uint64
	hits        uint64
	resets      uint64
	resetErrors uint64

	// Metrics
	name                 string
	metricsEnabled       bool
	trackObjectLifetime  bool
	lastStatsReport      time.Time
	statsReportInterval  time.Duration
}

func newPerformancePool[T any](config Config[T]) *performancePool[T] {
	p := &performancePool[T]{
		factory:             config.Factory,
		resetter:            config.Resetter,
		name:                config.Name,
		metricsEnabled:      config.EnableMetrics,
		trackObjectLifetime: config.TrackObjectLifetime,
		lastStatsReport:     time.Now(),
		statsReportInterval: 10 * time.Second, // Report stats every 10 seconds
	}

	p.pool = sync.Pool{
		New: func() interface{} {
			atomic.AddUint64(&p.misses, 1)
			if p.metricsEnabled {
				telemetry.Increment(nil, MetricGroupPool, MetricMiss, 
					metrics.Tag{Key: "pool", Value: p.name})
			}
			return p.factory()
		},
	}

	return p
}

func (p *performancePool[T]) Get() T {
	// Update stats
	atomic.AddUint64(&p.gets, 1)

	if p.metricsEnabled {
		telemetry.Increment(nil, MetricGroupPool, MetricGet, 
			metrics.Tag{Key: "pool", Value: p.name})
	}

	// Get object from pool
	obj := p.pool.Get().(T)

	// Track object lifetime if enabled
	if p.trackObjectLifetime && p.metricsEnabled {
		// This requires a way to track object creation time
		// We'll use a simple approach using a global map
		trackObjectCreation(obj, p.name)
	}

	// Report periodic stats
	p.maybeReportStats()

	return obj
}

func (p *performancePool[T]) Put(obj T) {
	// Skip nil objects
	if isNil(obj) {
		return
	}

	// Update stats
	atomic.AddUint64(&p.puts, 1)
	if p.metricsEnabled {
		telemetry.Increment(nil, MetricGroupPool, MetricPut, 
			metrics.Tag{Key: "pool", Value: p.name})
	}

	// Record object lifetime
	if p.trackObjectLifetime && p.metricsEnabled {
		if duration, ok := retrieveObjectLifetime(obj); ok {
			telemetry.Timing(nil, MetricGroupPool, MetricObjectLifetime, duration,
				metrics.Tag{Key: "pool", Value: p.name})
		}
	}

	// Reset the object
	resetErr := p.resetObject(obj)
	if resetErr != nil {
		atomic.AddUint64(&p.resetErrors, 1)
		return // Don't put broken objects back in pool
	}

	// Put object back in pool
	p.pool.Put(obj)

	// Report periodic stats
	p.maybeReportStats()
}

func (p *performancePool[T]) Stats() Stats {
	return Stats{
		Gets:        atomic.LoadUint64(&p.gets),
		Puts:        atomic.LoadUint64(&p.puts),
		Misses:      atomic.LoadUint64(&p.misses),
		Hits:        atomic.LoadUint64(&p.hits),
		Resets:      atomic.LoadUint64(&p.resets),
		ResetErrors: atomic.LoadUint64(&p.resetErrors),
	}
}

func (p *performancePool[T]) resetObject(obj T) error {
	// Try to use custom resetter if provided
	if p.resetter != nil {
		err := p.resetter(obj)
		if err != nil {
			if p.metricsEnabled {
				telemetry.Increment(nil, MetricGroupPool, MetricResetErrors, 
					metrics.Tag{Key: "pool", Value: p.name})
			}
			return err
		}

		atomic.AddUint64(&p.resets, 1)
		if p.metricsEnabled {
			telemetry.Increment(nil, MetricGroupPool, MetricResets, 
				metrics.Tag{Key: "pool", Value: p.name})
		}
		return nil
	}

	// Try to use Reset() method if T implements Resettable
	if r, ok := any(obj).(Resettable); ok {
		err := r.Reset()
		if err != nil {
			if p.metricsEnabled {
				telemetry.Increment(nil, MetricGroupPool, MetricResetErrors, 
					metrics.Tag{Key: "pool", Value: p.name})
			}
			return err
		}

		atomic.AddUint64(&p.resets, 1)
		if p.metricsEnabled {
			telemetry.Increment(nil, MetricGroupPool, MetricResets, 
				metrics.Tag{Key: "pool", Value: p.name})
		}
	}

	return nil
}

func (p *performancePool[T]) maybeReportStats() {
	if !p.metricsEnabled {
		return
	}

	// Only report stats periodically to reduce overhead
	now := time.Now()
	if now.Sub(p.lastStatsReport) < p.statsReportInterval {
		return
	}

	// Atomically update last report time
	// Using CompareAndSwap to ensure only one goroutine reports
	if atomic.CompareAndSwapUint64(
		(*uint64)(&p.lastStatsReport),
		uint64(p.lastStatsReport.UnixNano()),
		uint64(now.UnixNano()),
	) {
		// Report current counts as gauges
		stats := p.Stats()

		telemetry.Gauge(nil, MetricGroupPool, "get_count", float64(stats.Gets),
			metrics.Tag{Key: "pool", Value: p.name})

		telemetry.Gauge(nil, MetricGroupPool, "put_count", float64(stats.Puts),
			metrics.Tag{Key: "pool", Value: p.name})

		telemetry.Gauge(nil, MetricGroupPool, "miss_count", float64(stats.Misses),
			metrics.Tag{Key: "pool", Value: p.name})

		telemetry.Gauge(nil, MetricGroupPool, "hit_ratio", hitRatio(stats),
			metrics.Tag{Key: "pool", Value: p.name})
	}
}

// Calculate hit ratio as a percentage
func hitRatio(stats Stats) float64 {
	if stats.Gets == 0 {
		return 0
	}

	hits := stats.Gets - stats.Misses
	return float64(hits) / float64(stats.Gets) * 100
}

// Simple object lifetime tracking (use sync.Map for thread safety without locks)
var (
	objectCreationTimes sync.Map
)

func trackObjectCreation(obj interface{}, poolName string) {
	objectKey := getObjectKey(obj)
	objectCreationTimes.Store(objectKey, time.Now())
}

func retrieveObjectLifetime(obj interface{}) (time.Duration, bool) {
	objectKey := getObjectKey(obj)
	value, ok := objectCreationTimes.Load(objectKey)
	if !ok {
		return 0, false
	}

	// Remove from map to avoid memory leaks
	objectCreationTimes.Delete(objectKey)

	creationTime, ok := value.(time.Time)
	if !ok {
		return 0, false
	}

	return time.Since(creationTime), true
}

// Generate a unique key for each object
func getObjectKey(obj interface{}) uintptr {
	return getPointerValue(obj)
}

// Get pointer value for an object
func getPointerValue(obj interface{}) uintptr {
	// This is a simple implementation; a more robust one might use
	// reflect to handle different types
	return uintptr(getPointer(obj))
}

// Get pointer to object (implementation detail)
func getPointer(obj interface{}) unsafe.Pointer {
	return (*[2]unsafe.Pointer)(unsafe.Pointer(&obj))[1]
}

// isNil checks if an interface value is nil
func isNil(v interface{}) bool {
	return v == nil
}
