## Specialized Pools with Metrics

```go
package pool

// MapPool is a pool for maps with automatic clearing
type MapPool[K comparable, V any] interface {
	// Get retrieves a map from the pool
	Get() map[K]V

	// Put returns a map to the pool, automatically clearing it
	Put(m map[K]V)

	// Stats returns usage statistics
	Stats() Stats
}

// NewMapPool creates a pool for maps with automatic clearing
func NewMapPool[K comparable, V any](initialCapacity int, name string, enableMetrics bool) MapPool[K, V] {
	return &mapPool[K, V]{
		pool: New(Config[map[K]V]{
			Factory: func() map[K]V {
				return make(map[K]V, initialCapacity)
			},
			Resetter: func(m map[K]V) error {
				// Clear the map
				for k := range m {
					delete(m, k)
				}
				return nil
			},
			Name:          name,
			EnableMetrics: enableMetrics,
		}),
	}
}

type mapPool[K comparable, V any] struct {
	pool Pool[map[K]V]
}

func (mp *mapPool[K, V]) Get() map[K]V {
	return mp.pool.Get()
}

func (mp *mapPool[K, V]) Put(m map[K]V) {
	mp.pool.Put(m)
}

func (mp *mapPool[K, V]) Stats() Stats {
	return mp.pool.Stats()
}

// SlicePool is a pool for slices with automatic resetting
type SlicePool[T any] interface {
	// Get retrieves a slice from the pool
	Get() []T

	// Put returns a slice to the pool, automatically resetting length to 0
	Put(s []T)

	// Stats returns usage statistics
	Stats() Stats
}

// NewSlicePool creates a pool for slices
func NewSlicePool[T any](initialCapacity int, name string, enableMetrics bool) SlicePool[T] {
	return &slicePool[T]{
		pool: New(Config[[]T]{
			Factory: func() []T {
				return make([]T, 0, initialCapacity)
			},
			Resetter: func(s []T) error {
				return nil
			},
			Name:          name,
			EnableMetrics: enableMetrics,
		}),
	}
}

type slicePool[T any] struct {
	pool Pool[[]T]
}

func (sp *slicePool[T]) Get() []T {
	s := sp.pool.Get()
	// Ensure length is 0
	if len(s) > 0 {
		s = s[:0]
	}
	return s
}

func (sp *slicePool[T]) Put(s []T) {
	if s == nil {
		return
	}
	sp.pool.Put(s[:0]) // Reset length to 0
}

func (sp *slicePool[T]) Stats() Stats {
	return sp.pool.Stats()
}
