// IndexDocumentModelPool manages pools of IndexDocumentChangeModel objects
type IndexDocumentModelPool interface {
	// Get retrieves a model with fresh maps initialized
	Get() *IndexDocumentChangeModel

	// Put returns a model to the pool
	Put(model *IndexDocumentChangeModel)

	// Stats returns usage statistics
	Stats() pool.Stats
}

// Create a new IndexDocumentModelPool
func NewIndexDocumentModelPool(enableMetrics bool) IndexDocumentModelPool {
	propertiesPool := pool.NewMapPool[string, any](16, "doc_properties", enableMetrics)
	documentKeysPool := pool.NewMapPool[string, any](8, "doc_keys", enableMetrics)
	metadataPool := pool.NewMapPool[string, any](8, "doc_metadata", enableMetrics)

	return &indexDocModelPool{
		modelPool: pool.New(pool.Config[*IndexDocumentChangeModel]{
			Factory: func() *IndexDocumentChangeModel {
				model := &IndexDocumentChangeModel{
					Properties:    propertiesPool.Get(),
					DocumentKeys:  documentKeysPool.Get(),
					EventMetadata: metadataPool.Get(),
					PartialKey:    make([]string, 0, 4),
				}

				if enableMetrics {
					telemetry.MeasureWithResult(nil, MetricGroupModels, MetricObjectCreation, 
						func() interface{} { return model },
						metrics.Tag{Key: "type", Value: "IndexDocumentChangeModel"})
				}

				return model
			},
			Resetter: func(model *IndexDocumentChangeModel) error {
				// Return maps to their pools
				if model.Properties != nil {
					propertiesPool.Put(model.Properties)
				}
				if model.DocumentKeys != nil {
					documentKeysPool.Put(model.DocumentKeys)
				}
				if model.EventMetadata != nil {
					metadataPool.Put(model.EventMetadata)
				}

				// Reset all scalar fields
				model.IndexKey = ""
				model.Op = ""
				model.Merged = false
				model.MergedIntoCorrelationId = ""
				model.MergedIntoPayloadSchemaName = ""
				model.DocumentId = ""
				model.RoutingId = ""
				model.TenantUuid = ""
				model.CorrelationId = ""
				model.PublicSchemaVersion = ""
				model.FullStateEvent = nil
				model.SnapshotEvent = nil
				model.PayloadSchemaName = ""
				model.PayloadPartIndex = 0
				model.PayloadPartCount = 0
				model.Timestamp = nil
				model.QueryGenerator = nil
				model.MessageModel = nil
				model.IsPartialDocument = false

				// Clear any slices
				if model.PartialKey != nil && len(model.PartialKey) > 0 {
					model.PartialKey = model.PartialKey[:0]
				}

				model.isStandaloneDocument = false
				model.MinimumViableKey = ""
				model.LogContext = nil
				model.SequenceNumberDocId = nil
				model.SequenceNumberIdToDriftStateMap = nil
				model.IndexMetaData = nil
				model.RootCacheId = ""

				// Clear document key map
				model.MergedIntoDocumentKey = nil

				return nil
			},
			Name:                "index_doc_model",
			EnableMetrics:       enableMetrics,
			TrackObjectLifetime: enableMetrics,
		}),
		propertiesPool:   propertiesPool,
		documentKeysPool: documentKeysPool,
		metadataPool:     metadataPool,
	}
}

type indexDocModelPool struct {
	modelPool        pool.Pool[*IndexDocumentChangeModel]
	propertiesPool   pool.MapPool[string, any]
	documentKeysPool pool.MapPool[string, any]
	metadataPool     pool.MapPool[string, any]
}

func (p *indexDocModelPool) Get() *IndexDocumentChangeModel {
	model := p.modelPool.Get()

	// Initialize fresh maps
	model.Properties = p.propertiesPool.Get()
	model.DocumentKeys = p.documentKeysPool.Get()
	model.EventMetadata = p.metadataPool.Get()

	return model
}

func (p *indexDocModelPool) Put(model *IndexDocumentChangeModel) {
	if model == nil {
		return
	}
	p.modelPool.Put(model)
}

func (p *indexDocModelPool) Stats() pool.Stats {
	return p.modelPool.Stats()
}

// MessageModelPool manages pools of MessageModel objects
type MessageModelPool interface {
	// Get retrieves a message model with changes map initialized
	Get() *MessageModel

	// Put returns a model to the pool
	Put(model *MessageModel)

	// Clean releases a model and all its document models back to their pools
	Clean(model *MessageModel, docPool IndexDocumentModelPool)

	// Stats returns usage statistics
	Stats() pool.Stats
}

// Create a new MessageModelPool
func NewMessageModelPool(enableMetrics bool) MessageModelPool {
	changesPool := pool.NewMapPool[string, []*IndexDocumentChangeModel](8, "changes_map", enableMetrics)
	slicePool := pool.NewSlicePool[*IndexDocumentChangeModel](8, "doc_slice", enableMetrics)

	return &messageModelPool{
		modelPool: pool.New(pool.Config[*MessageModel]{
			Factory: func() *MessageModel {
				model := &MessageModel{
					Changes: changesPool.Get(),
				}

				if enableMetrics {
					telemetry.MeasureWithResult(nil, MetricGroupModels, MetricObjectCreation, 
						func() interface{} { return model },
						metrics.Tag{Key: "type", Value: "MessageModel"})
				}

				return model
			},
			Resetter: func(model *MessageModel) error {
				// Return changes map to its pool
				if model.Changes != nil {
					changesPool.Put(model.Changes)
				}

				// Clear key and references
				model.Key = nil
				model.OriginalMessage = nil
				model.DeadLetterMessage = nil
				model.LogContext = nil

				return nil
			},
			Name:                "message_model",
			EnableMetrics:       enableMetrics,
			TrackObjectLifetime: enableMetrics,
		}),
		changesPool: changesPool,
		slicePool:   slicePool,
	}
}

type messageModelPool struct {
	modelPool   pool.Pool[*MessageModel]
	changesPool pool.MapPool[string, []*IndexDocumentChangeModel]
	slicePool   pool.SlicePool[*IndexDocumentChangeModel]
}

func (p *messageModelPool) Get() *MessageModel {
	model := p.modelPool.Get()
	model.Changes = p.changesPool.Get()
	return model
}

func (p *messageModelPool) Put(model *MessageModel) {
	if model == nil {
		return
	}
	p.modelPool.Put(model)
}

func (p *messageModelPool) Clean(model *MessageModel, docPool IndexDocumentModelPool) {
	if model == nil {
		return
	}

	// First put all document models back to their pool
	for _, docs := range model.Changes {
		for _, doc := range docs {
			docPool.Put(doc)
		}
	}

	// Then put the message model back
	p.Put(model)
}

func (p *messageModelPool) Stats() pool.Stats {
	return p.modelPool.Stats()
}
