## Feature Flag Integration

```go
package processor

import (
	"airwatch/uem/gumdrop-ingestion/pkg/feature"
	"airwatch/uem/gumdrop-ingestion/pkg/log"
	"airwatch/uem/gumdrop-ingestion/pkg/models"
	"airwatch/uem/gumdrop-ingestion/pkg/pool"
	"airwatch/uem/gumdrop-ingestion/pkg/streaming"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry"
	"airwatch/uem/gumdrop-ingestion/pkg/telemetry/metrics"
	"runtime"
	"time"
)

const (
	PoolingFeature = "object-pooling"
	MetricGroupProcessor = "processor"
	MetricAllocation = "memory_allocation"
)

// ModelFactory handles creating models with or without pooling based on feature flags
type ModelFactory struct {
	docPool  models.IndexDocumentModelPool
	msgPool  models.MessageModelPool
	poolingEnabled func() bool
	metricsEnabled bool
}

// NewModelFactory creates a factory that respects feature flags
func NewModelFactory(metricsEnabled bool) *ModelFactory {
	docPool := models.NewIndexDocumentModelPool(metricsEnabled)
	msgPool := models.NewMessageModelPool(metricsEnabled)

	return &ModelFactory{
		docPool:        docPool,
		msgPool:        msgPool,
		poolingEnabled: func() bool { return feature.IsEnabled(PoolingFeature) },
		metricsEnabled: metricsEnabled,
	}
}

// GetDocumentModel creates or gets from pool
func (f *ModelFactory) GetDocumentModel() *models.IndexDocumentChangeModel {
	if f.poolingEnabled() {
		return f.docPool.Get()
	}

	// No pooling - direct allocation
	model := &models.IndexDocumentChangeModel{
		Properties:    make(map[string]any),
		DocumentKeys:  make(map[string]any),
		EventMetadata: make(map[string]any),
		PartialKey:    make([]string, 0, 4),
	}

	if f.metricsEnabled {
		telemetry.MeasureWithResult(nil, MetricGroupModels, MetricObjectCreation, 
			func() interface{} { return model },
			metrics.Tag{Key: "type", Value: "IndexDocumentChangeModel"},
			metrics.Tag{Key: "pooled", Value: "false"})
	}

	return model
}

// PutDocumentModel returns to pool or lets GC handle it
func (f *ModelFactory) PutDocumentModel(model *models.IndexDocumentChangeModel) {
	if model == nil || !f.poolingEnabled() {
		return
	}

	f.docPool.Put(model)
}

// GetMessageModel creates or gets from pool
func (f *ModelFactory) GetMessageModel() *models.MessageModel {
	if f.poolingEnabled() {
		return f.msgPool.Get()
	}

	// No pooling - direct allocation
	model := &models.MessageModel{
		Changes: make(map[string][]*models.IndexDocumentChangeModel),
	}

	if f.metricsEnabled {
		telemetry.MeasureWithResult(nil, MetricGroupModels, MetricObjectCreation, 
			func() interface{} { return model },
			metrics.Tag{Key: "type", Value: "MessageModel"},
			metrics.Tag{Key: "pooled", Value: "false"})
	}

	return model
}

// PutMessageModel returns to pool or lets GC handle it
func (f *ModelFactory) PutMessageModel(model *models.MessageModel) {
	if model == nil || !f.poolingEnabled() {
		return
	}

	f.msgPool.Put(model)
}

// CleanupMessageModel returns a message and all its documents to pools
func (f *ModelFactory) CleanupMessageModel(model *models.MessageModel) {
	if model == nil || !f.poolingEnabled() {
		return
	}

	f.msgPool.Clean(model, f.docPool)
}

// CollectPoolStats captures and reports important pool stats
func (f *ModelFactory) CollectPoolStats(logContext *log.Context) {
	if !f.metricsEnabled {
		return
	}

	// Get stats from pools
	docStats := f.docPool.Stats()
	msgStats := f.msgPool.Stats()

	// Report document model pool stats
	telemetry.Gauge(logContext, MetricGroupPool, "hit_ratio", hitRatio(docStats),
		metrics.Tag{Key: "pool", Value: "index_doc_model"})

	// Report message model pool stats
	telemetry.Gauge(logContext, MetricGroupPool, "hit_ratio", hitRatio(msgStats),
		metrics.Tag{Key: "pool", Value: "message_model"})
}

// Helper to calculate hit ratio
func hitRatio(stats pool.Stats) float64 {
	if stats.Gets == 0 {
		return 0
	}

	hits := stats.Gets - stats.Misses
	return float64(hits) / float64(stats.Gets) * 100
}

// Modified processor method with pooling support
func (mp *messageProcessor) NewMessageCallback(
	logContext *log.Context,
	tpo *streaming.TopicPartitionOffset,
	key []byte,
	message []byte,
	headers streaming.MessageHeaders,
) {
	// Track memory allocations before processing
	var startAllocs runtime.MemStats
	if mp.factory.metricsEnabled {
		runtime.ReadMemStats(&startAllocs)
	}

	// Transform using factory (pooled or not based on feature flag)
	item, err := telemetry.MeasureWithResultAndError(
		logContext,
		MetricGroupProcessor,
		"transform",
		func() (*models.MessageModel, error) {
			return mp.transform(tpo, message, headers)
		},
		metrics.Tag{Key: "pooled", Value: f.poolingEnabled()},
	)

	// Track memory allocations after processing
	if mp.factory.metricsEnabled {
		var endAllocs runtime.MemStats
		runtime.ReadMemStats(&endAllocs)
		allocDiff := endAllocs.TotalAlloc - startAllocs.TotalAlloc

		telemetry.Gauge(logContext, MetricGroupProcessor, MetricAllocation, float64(allocDiff),
			metrics.Tag{Key: "operation", Value: "transform"},
			metrics.Tag{Key: "pooled", Value: f.poolingEnabled()})
	}

	if err != nil {
		// Handle error
		if item != nil {
			mp.factory.CleanupMessageModel(item)
		}
		return
	}

	// Add to processing queue
	mp.queue.Enqueue(item)
}

