# Refined Pool Implementation with Go 1.23 Features

Here's an updated implementation using Go 1.23.4 features, with cleaner naming and atomic types:

```go
package pool

import (
	"sync"
	"sync/atomic"
	"time"
	"unsafe"
)

// Pool is the primary interface for object pooling
type Pool[T any] interface {
	// Get retrieves an object from the pool or creates a new one
	Get() T

	// Put returns an object to the pool
	Put(obj T)

	// Stats returns current pool statistics
	Stats() Stats
}

// Stats provides information about pool usage
type Stats struct {
	Gets        uint64
	Puts        uint64
	Misses      uint64
	Hits        uint64
	Resets      uint64
	ResetErrors uint64
}

// Resettable interface for objects that need cleanup before reuse
type Resettable interface {
	// Reset prepares an object for reuse
	Reset() error
}

// Configuration options for creating pools
type Config[T any] struct {
	// Factory creates new objects when the pool is empty
	Factory func() T

	// Resetter is called when objects are returned to the pool
	// If not provided and T implements Resettable, that will be used instead
	Resetter func(T) error

	// Name identifies the pool (for metrics and debugging)
	Name string

	// EnableMetrics toggles metrics collection
	EnableMetrics bool
}

// New creates a new object pool with the given configuration
func New[T any](config Config[T]) Pool[T] {
	return newGenericPool(config)
}

// Implementation

type genericPool[T any] struct {
	pool     sync.Pool
	factory  func() T
	resetter func(T) error
	name     string

	// Stats using atomic types (Go 1.19+)
	gets        atomic.Uint64
	puts        atomic.Uint64
	misses      atomic.Uint64
	hits        atomic.Uint64
	resets      atomic.Uint64
	resetErrors atomic.Uint64
}

func newGenericPool[T any](config Config[T]) *genericPool[T] {
	p := &genericPool[T]{
		factory:  config.Factory,
		resetter: config.Resetter,
		name:     config.Name,
	}

	p.pool = sync.Pool{
		New: func() interface{} {
			p.misses.Add(1)
			return p.factory()
		},
	}

	return p
}

func (p *genericPool[T]) Get() T {
	// Update stats
	p.gets.Add(1)

	// Get object from pool
	obj := p.pool.Get().(T)

	return obj
}

func (p *genericPool[T]) Put(obj T) {
	// Skip nil objects
	if isNil(obj) {
		return
	}

	// Update stats
	p.puts.Add(1)

	// Reset the object
	resetErr := p.resetObject(obj)
	if resetErr != nil {
		p.resetErrors.Add(1)
		return // Don't put broken objects back in pool
	}

	// Put object back in pool
	p.pool.Put(obj)
}

func (p *genericPool[T]) Stats() Stats {
	return Stats{
		Gets:        p.gets.Load(),
		Puts:        p.puts.Load(),
		Misses:      p.misses.Load(),
		Hits:        p.gets.Load() - p.misses.Load(),
		Resets:      p.resets.Load(),
		ResetErrors: p.resetErrors.Load(),
	}
}

func (p *genericPool[T]) resetObject(obj T) error {
	// Try to use custom resetter if provided
	if p.resetter != nil {
		err := p.resetter(obj)
		if err != nil {
			return err
		}

		p.resets.Add(1)
		return nil
	}

	// Try to use Reset() method if T implements Resettable
	if r, ok := any(obj).(Resettable); ok {
		err := r.Reset()
		if err != nil {
			return err
		}

		p.resets.Add(1)
	}

	return nil
}

// isNil checks if an interface value is nil
func isNil(v interface{}) bool {
	return v == nil
}
```

